<!DOCTYPE html>
<html>
<head>
  <title>Falling Sand Simulation</title>
  <style>
    body {
      background-color: #1e1e1e;
      display: flex;
      justify-content: center;
      align-items: center;
      height: 100vh;
      margin: 0;
      font-family: sans-serif;
    }

    #container {
      position: relative;
    }

    canvas {
      border: 1px solid #555;
      background-color: #282c34;
    }

    .button {
      display: inline-block;
      padding: 10px 20px;
      margin: 5px;
      font-size: 16px;
      cursor: pointer;
      background-color: #3e4451;
      color: #d8dee9;
      border: none;
      border-radius: 5px;
    }

    .button:hover {
      background-color: #434c5e;
    }
  </style>
</head>
<body>
  <div id="container">
    <canvas id="sand"></canvas>
    <div>
      <button class="button" id="mat-sand">Sand</button>
      <button class="button" id="mat-water">Water</button>
      <button class="button" id="mat-wall">Wall</button>
      <button class="button" id="mat-acid">Acid</button>
      <button class="button" id="mat-empty">Empty (Eraser)</button>
      <button class="button" id="clear">Clear</button>
    </div>
  </div>

  <script>
    const canvas = document.getElementById('sand');
    const ctx = canvas.getContext('2d');
    const w = 80;
    const h = 60;
    let grid = [];
    let mouseX = 0;
    let mouseY = 0;

    function init() {
      canvas.width = 400;
      canvas.height = 400;
      grid = Array(h).fill(null).map(() => Array(w).fill('empty'));
    }

    function draw() {
      ctx.fillStyle = '#282c34';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
          const material = grid[y][x];
          if (material === 'sand') {
            ctx.fillStyle = '#FFA500'; // Orange
          } else if (material === 'water') {
            ctx.fillStyle = '#4682B4'; // Steel Blue
          } else if (material === 'wall') {
            ctx.fillStyle = '#808080'; // Gray
          } else if (material === 'acid') {
            ctx.fillStyle = '#A52A2A'; // Brown
          } else {
            ctx.fillStyle = '#3e4451'; // Dark Gray
          }

          ctx.fillRect(x * 10, y * 10, 10, 10);
        }
      }
    }

    function tick(n) {
      for (let y = h - 1; y >= 0; y--) {
        for (let x = 0; x < w; x++) {
          const currentMaterial = grid[y][x];

          if (currentMaterial === 'sand') {
            // Sand falls down
            let nextY = y + 1;
            if (nextY < h && grid[nextY][x] === 'empty') {
              grid[nextY][x] = 'sand';
              grid[y][x] = 'empty';
            } else {
              // Sand slides diagonally down-left/right
              let dir = Math.random() < 0.5 ? -1 : 1;
              let nextX = x + dir;
              if (nextX >= 0 && nextX < w && grid[y][nextX] === 'empty') {
                grid[nextY][nextX] = 'sand';
                grid[y][x] = 'empty';
              }
            }
          } else if (currentMaterial === 'water') {
            // Water falls horizontally
            let nextX = x + 1;
            if (nextX < w && grid[y][nextX] === 'empty') {
              grid[y][nextX] = 'water';
              grid[y][x] = 'empty';
            } else {
              // Water spreads sideways
              let dir = Math.random() < 0.5 ? -1 : 1;
              nextX = x + dir;
              if (nextX >= 0 && nextX < w && grid[y][nextX] === 'empty') {
                grid[y][nextX] = 'water';
                grid[y][x] = 'empty';
              }
            }
          } else if (currentMaterial === 'acid') {
            // Acid moves like water and dissolves sand/wall
            let nextY = y + 1;
            if (nextY < h && grid[nextY][x] === 'empty') {
              grid[nextY][x] = 'water';
              grid[y][x] = 'empty';
            } else {
              let dir = Math.random() < 0.5 ? -1 : 1;
              let nextX = x + dir;
              if (nextX >= 0 && nextX < w) {
                const targetMaterial = grid[y][nextX];
                if (targetMaterial === 'sand' || targetMaterial === 'wall') {
                  grid[y][nextX] = 'empty';
                } else {
                  grid[nextY][nextX] = 'water';
                  grid[y][x] = 'empty';
                }
              }
            }
          }
        }
      }
    }

    function set(x, y, material) {
      if (x >= 0 && x < w && y >= 0 && y < h) {
        grid[y][x] = material;
      }
    }

    function get(x, y) {
      if (x >= 0 && x < w && y >= 0 && y < h) {
        return grid[y][x];
      }
      return 'empty';
    }

    function clear() {
      for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
          grid[y][x] = 'empty';
        }
      }
    }

    document.getElementById('mat-sand').addEventListener('click', () => set(mouseX, mouseY, 'sand'));
    document.getElementById('mat-water').addEventListener('click', () => set(mouseX, mouseY, 'water'));
    document.getElementById('mat-wall').addEventListener('click', () => set(mouseX, mouseY, 'wall'));
    document.getElementById('mat-acid').addEventListener('click', () => set(mouseX, mouseY, 'acid'));
    document.getElementById('mat-empty').addEventListener('click', () => set(mouseX, mouseY, 'empty'));
    document.getElementById('clear').addEventListener('click', () => clear());

    canvas.addEventListener('mousedown', (e) => {
      mouseX = Math.round(e.offsetX / 10);
      mouseY = Math.round(e.offsetY / 10);
    });

    canvas.addEventListener('mousemove', (e) => {
      if (e.buttons === 'mousedown') {
        mouseX = Math.round(e.offsetX / 10);
        mouseY = Math.round(e.offsetY / 10);
      }
    });

    init();
    draw();

    window.sim = {
      w,
      h,
      tick: tick,
      get: get,
      set: set,
      clear: clear
    };

    function animate() {
      tick(1);
      draw();
      requestAnimationFrame(animate);
    }

    animate();
  </script>
</body>
</html>
